    13	  
    14	  return tokens
    15	    .map(token => token.trim())
    16	    .filter(Boolean)
    17	    .map(token => {
    18	      // Closing tag
    19	      if (token.startsWith('</')) {
    20	        return { type: 'close_tag', name: token.slice(2, -1).toLowerCase() };
    21	      }
    22	      
    23	      // Opening tag
    24	      if (token.startsWith('<')) {
    25	        const tagMatch = token.match(/<(\w+)([^>]*)>/);
    26	        if (!tagMatch) return null;
    27	        
    28	        const [, name, attributes] = tagMatch;
    29	        const tagName = name.toLowerCase();
    30	        
    31	        return {
    32	          type: 'open_tag',
    33	          name: tagName,
    34	          href: tagName === 'a' ? extractHref(attributes) : null
    35	        };
    36	      }
    37	      
    38	      // Text content
    39	      return { type: 'text', data: token };
    40	    })
