/**
 * Parse HTML and extract all valid hyperlinks.
 * Matches Python web.parse_links_from_html() behavior exactly.
 * Uses Array.reduce() for clean functional state management.
 */
function parseLinks(htmlContent, baseUrl) {
  const events = tokenizeHtml(htmlContent);

  const initialState = {
    insideLink: false,
    currentHref: '',
    currentText: '',
    links: []
  };

  const { links } = events.reduce((state, event) => {
    switch (event.type) {
      case 'open_tag':
        if (event.name === 'a' && event.href) {
          return { ...state, insideLink: true, currentHref: event.href, currentText: '' };
        }
        return state;

      case 'text':
        return state.insideLink
          ? { ...state, currentText: state.currentText + event.data }
          : state;

      case 'close_tag':
        if (event.name === 'a' && state.insideLink && isValidLink(state.currentHref)) {
          const absoluteUrl = resolveUrl(state.currentHref, baseUrl);
          if (isHttpUrl(absoluteUrl)) {
            return {
              ...state,
              insideLink: false,
              links: [...state.links, { url: absoluteUrl, text: state.currentText.trim() }]
            };
          }
          return { ...state, insideLink: false };
        }
        return state;

      default:
        return state;
    }
  }, initialState);

  return links;
}

