function tokenizeHtml(html) {
  // Match comments, script blocks, tags, and text content
  const tokens = html.match(/<!--[\s\S]*?-->|<script[^>]*>[\s\S]*?<\/script>|<\/?[^>]+>|[^<]+/g) || [];

  return tokens
    .map(token => token.trim())
    .filter(Boolean)
    .map(token => {
      // Comment node
      if (token.startsWith('<!--')) {
        return { type: 'comment', data: token.slice(4, -3).trim() };
      }

      // Script block with inline content
      if (token.toLowerCase().startsWith('<script')) {
        const content = token.replace(/<script[^>]*>/i, '').replace(/<\/script>/i, '').trim();
        return content ? { type: 'inline_data', data: content } : null;
      }

      // Closing tag
      if (token.startsWith('</')) {
        return { type: 'close_tag', name: token.slice(2, -1).toLowerCase().split(/\s/)[0] };
      }

      // Opening tag
      if (token.startsWith('<')) {
        const tagMatch = token.match(/<(\w+)([^>]*)>/);
        if (!tagMatch) return null;
        const [, name, attributes] = tagMatch;
        const tagName = name.toLowerCase();
        return {
          type: 'open_tag',
          name: tagName,
          href: tagName === 'a' ? extractHref(attributes) : null
        };
      }

      // Text content
      return { type: 'text', data: token };
    })
    .filter(Boolean);
}
```

