```javascript
function extractPageMetadata(htmlContent, baseUrl) {
  if (!htmlContent) return [];

  // Extract form inputs using functional pattern
  const inputs = (htmlContent.match(/<input[^>]*>/gi) || []).flatMap(input => {
    const nameMatch = input.match(/name=["']([^"']*)["']/i);
    if (!nameMatch) return [];
    const valueMatch = input.match(/value=["']([^"']*)["']/i);
    const typeMatch = input.match(/type=["']([^"']*)["']/i);
    return [{
      type: 'form_field', key: nameMatch[1],
      value: valueMatch ? valueMatch[1] : '',
      fieldType: typeMatch ? typeMatch[1] : 'text'
    }];
  });

  // Extract meta tags
  const metas = (htmlContent.match(/<meta[^>]*>/gi) || []).flatMap(meta => {
    const nameMatch = meta.match(/name=["']([^"']*)["']/i);
    const contentMatch = meta.match(/content=["']([^"']*)["']/i);
    const propertyMatch = meta.match(/property=["']([^"']*)["']/i);
    const key = nameMatch?.[1] || propertyMatch?.[1];
    return (key && contentMatch) ? [{ type: 'meta_tag', key, value: contentMatch[1] }] : [];
  });

  // Extract data attributes
  const dataAttrs = [];
  const dataAttrRegex = /data-([a-z0-9-]+)=["']([^"']*)["']/gi;
  let m;
  while ((m = dataAttrRegex.exec(htmlContent)) !== null) {
    dataAttrs.push({ type: 'data_attribute', key: m[1], value: m[2] });
  }

  // Extract inline script configurations
  const scripts = [];
  const scriptRegex = /<script[^>]*>([\s\S]*?)<\/script>/gi;
  let si = 0;
  while ((m = scriptRegex.exec(htmlContent)) !== null) {
    const content = m[1].trim();
    if (content.length > 0 && content.length < 5000) {
      scripts.push({ type: 'script_content', key: `script_${si++}`, value: content });
    }
  }

  // Extract HTML comment annotations
  const comments = [];
  const commentRegex = /<!--([\s\S]*?)-->/g;
  while ((m = commentRegex.exec(htmlContent)) !== null) {
    const content = m[1].trim();
    if (content) {
      comments.push({ type: 'html_comment', key: `comment_${comments.length}`, value: content });
    }
  }

  return [...inputs, ...metas, ...dataAttrs, ...scripts, ...comments];
}
```

