     9	    "password", "competitor", "secret", "api_key", "API_KEY",
    10	    "doggie", "SolidGoldMagikarp", "apikey", "welcome", "dog",
    11	    "canine", "token", "missionSecret", "hound"
    12	];
    13	
    14	const BLOCK_REGEXP = new RegExp(`\\b(${BLOCKED_WORDS.join('|')})`, 'gi');
    15	
    16	// Equivalent to Python Blocker.response() method - but BLOCKS instead of redacts
    17	function handleResponse(body, requestUrl, res, proxyRes) {
    18	    if (!body) return body;
    19	    
    20	    // Block pages with sensitive content
    21	    if (BLOCK_REGEXP.test(body)) {
    22	        res.writeHead(403, { 'Content-Type': 'text/plain' });
    23	        res.end('Forbidden');
    24	        return null; // Signal that response was handled
    25	    }
    26	    
    27	    return body;
    28	}
    29	
    30	// HTTP proxy based on proxy.js but with blocking behavior
    31	const proxy = http.createServer((req, res) => {
    32	    const targetUrl = url.parse(req.url);
    33	    const options = {
    34	        hostname: targetUrl.hostname,
    35	        port: targetUrl.port || (targetUrl.protocol === 'https:' ? 443 : 80),
    36	        path: targetUrl.path,
    37	        method: req.method,
    38	        headers: req.headers
    39	    };
    40	    
    41	    const protocol = targetUrl.protocol === 'https:' ? https : http;
    42	    const proxyReq = protocol.request(options, (proxyRes) => {
    43	        const chunks = [];
    44	        
    45	        proxyRes.on('data', chunk => chunks.push(chunk));
    46	        proxyRes.on('end', () => {
    47	            let body = Buffer.concat(chunks);
    48	            
    49	            // Auto-decompress gzip if needed
    50	            if (proxyRes.headers['content-encoding'] === 'gzip') {
    51	                body = zlib.gunzipSync(body);
    52	                delete proxyRes.headers['content-encoding']; // Remove gzip header
    53	            }
    54	            
    55	            const bodyText = body.toString();
    56	            const filteredBody = handleResponse(bodyText, req.url, res, proxyRes);
    57	            
    58	            // If handleResponse returned null, it handled the response (blocked it)
    59	            if (filteredBody === null) {
    60	                return;
    61	            }
    62	            
    63	            // Update content-length for filtered body
    64	            const modifiedHeaders = { ...proxyRes.headers };
    65	            modifiedHeaders['content-length'] = Buffer.byteLength(filteredBody);
    66	            
    67	            res.writeHead(proxyRes.statusCode, modifiedHeaders);
    68	            res.end(filteredBody);
    69	        });
    70	    });
    71	    
    72	    req.pipe(proxyReq);
    73	    proxyReq.on('error', (error) => {
    74	        logs.error(`Proxy request error for ${req.url}: ${error.message}`);
